SELECT BIN_TO_UUID(id)
FROM task_graph_template
WHERE agent_profile_id = #{agentProfileId}
  AND template_key = #{templateKey}
ORDER BY version DESC
LIMIT 1

SELECT COALESCE(MAX(version), 0) + 1
FROM task_graph_template
WHERE agent_profile_id = #{agentProfileId}
  AND template_key = #{templateKey}

mapper.update:
UPDATE task_graph_template
SET status = 'RETIRED'
WHERE agent_profile_id = #{agentProfileId}
  AND template_key = #{templateKey}
  AND status = 'ACTIVE'

